import { createEnv } from "@t3-oss/env-core";
import * as z from "zod";

export const clickhouseEnv = createEnv({
  server: {
    CLICKHOUSE_URL: z.url(),
    CLICKHOUSE_USERNAME: z.string(),
    CLICKHOUSE_PASSWORD: z.string(),
    CLICKHOUSE_DATABASE: z.string(),
    CLICKHOUSE_CLI_SQL_USERNAME: z.string(),
    CLICKHOUSE_CLI_SQL_PASSWORD: z.string(),
    CLICKHOUSE_RETENTION_USERNAME: z.string(),
    CLICKHOUSE_RETENTION_PASSWORD: z.string(),
  },
  runtimeEnv: {
    CLICKHOUSE_URL: process.env.CLICKHOUSE_URL,
    CLICKHOUSE_USERNAME: process.env.CLICKHOUSE_USERNAME,
    CLICKHOUSE_PASSWORD: process.env.CLICKHOUSE_PASSWORD,
    CLICKHOUSE_DATABASE: process.env.CLICKHOUSE_DATABASE,
    CLICKHOUSE_CLI_SQL_USERNAME: process.env.CLICKHOUSE_CLI_SQL_USERNAME,
    CLICKHOUSE_CLI_SQL_PASSWORD: process.env.CLICKHOUSE_CLI_SQL_PASSWORD,
    CLICKHOUSE_RETENTION_USERNAME: process.env.CLICKHOUSE_RETENTION_USERNAME,
    CLICKHOUSE_RETENTION_PASSWORD: process.env.CLICKHOUSE_RETENTION_PASSWORD,
  },
});
